#!python

import win32pipe
import win32api
import win32file
import time
import threading
import sys

MSG_SIZE=4096

serverPipe = win32pipe.CreateNamedPipe(
    "\\\\.\\pipe\\DebugServer",
    win32pipe.PIPE_ACCESS_DUPLEX,
    win32pipe.PIPE_TYPE_MESSAGE | win32pipe.PIPE_READMODE_MESSAGE,
    win32pipe.PIPE_UNLIMITED_INSTANCES,
    MSG_SIZE,
    MSG_SIZE,
    10 * 1000,
    None)
while True:
    win32pipe.ConnectNamedPipe(serverPipe, None)
    (ret, data) = win32file.ReadFile(serverPipe, MSG_SIZE)
    print(data.decode())
    sys.stdout.flush()

    try:
        win32file.WriteFile(serverPipe, b'OK')
    except:
        pass
    win32pipe.DisconnectNamedPipe(serverPipe)
